const row = $json;
return [{
  json: {
    ...row,
    hasDomain: !!(row.domain && row.domain.trim())
  }
}];

const row = $('Check Domain').item.json;
const existing = row.enrichment || {};
const skippedPage = { status: 'skipped', text: '', url: null, reason: 'no_domain' };

const enrichment = {
  ...existing,
  website: {
    status: 'skipped',
    pages: {
      home: skippedPage,
      about: skippedPage,
      pricing: skippedPage
    },
    fetched_at: null
  }
};

return [{ json: { id: row.id, enrichment } }];

// Absent, unreachable, or unparseable robots.txt is treated as permissive
// (absent = allowed) so this can never itself break enrichment (see docs/DECISIONS.md).
const resp = $json;
const disallowed = [];

if (resp.statusCode && resp.statusCode < 400 && typeof resp.body === 'string') {
  let inWildcardBlock = false;
  for (const raw of resp.body.split(/\r?\n/)) {
    const line = raw.split('#')[0].trim();
    if (!line) continue;
    const sepIdx = line.indexOf(':');
    if (sepIdx === -1) continue;
    const key = line.slice(0, sepIdx).trim().toLowerCase();
    const value = line.slice(sepIdx + 1).trim();
    if (key === 'user-agent') {
      inWildcardBlock = value === '*';
    } else if (key === 'disallow' && inWildcardBlock && value) {
      disallowed.push(value);
    }
  }
}

const row = $('Check Domain').item.json;
return [{
  json: {
    id: row.id,
    domain: row.domain.trim(),
    enrichment: row.enrichment || {},
    disallowedPrefixes: disallowed
  }
}];

const row = $json;
const base = `https://${row.domain}`;
const disallowed = row.disallowedPrefixes || [];

function isAllowed(path) {
  return !disallowed.some((prefix) => path.startsWith(prefix));
}

const plan = [
  { pageType: 'home', primaryPath: '/', fallbackPath: null },
  { pageType: 'about', primaryPath: '/about', fallbackPath: '/about-us' },
  { pageType: 'pricing', primaryPath: '/pricing', fallbackPath: '/plans' }
];

return plan.map((p) => ({
  json: {
    pageType: p.pageType,
    primaryUrl: base + p.primaryPath,
    primaryAllowed: isAllowed(p.primaryPath),
    fallbackUrl: p.fallbackPath ? base + p.fallbackPath : null,
    fallbackAllowed: p.fallbackPath ? isAllowed(p.fallbackPath) : false
  }
}));

const pageResults = $input.all().map((i) => i.json);
const pages = {};
for (const r of pageResults) {
  pages[r.pageType] = {
    status: r.status,
    text: r.text || '',
    url: r.url || null,
    ...(r.reason ? { reason: r.reason } : {})
  };
}

const statuses = Object.values(pages).map((p) => p.status);
const okCount = statuses.filter((s) => s === 'ok').length;
let websiteStatus;
if (okCount === statuses.length) websiteStatus = 'ok';
else if (okCount === 0) websiteStatus = 'failed';
else websiteStatus = 'partial';

const row = $('Parse robots.txt').first().json;
const existing = row.enrichment || {};

const enrichment = {
  ...existing,
  website: {
    status: websiteStatus,
    pages,
    fetched_at: new Date().toISOString()
  }
};

return [{ json: { id: row.id, enrichment } }];
